SELECT  order_item.id, order_item.order_id,order_item.product_id,product.name as productname,order_item.price,order_item.quantity,order_item.amount,order_item.remark
FROM order_item inner join  product  on order_item.product_id = product.id
WHERE order_id = #{orderid}

SELECT 

FROM order_item
WHERE 1=1

  AND id = #{id}


  AND order_id = #{oid}


  AND product_id IN (
    SELECT id FROM product WHERE name LIKE CONCAT('%', #{name}, '%')
  )


  AND order_id IN (
    SELECT id FROM `order` WHERE phone LIKE CONCAT('%', #{phone}, '%')
  )
